                    >
                      {test.name}
                    </text>
                  </g>
                ))}
              </svg>
            </div>

            {/* Test Overview Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              {tests.map((test, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.1 }}
                  whileHover={{ y: -5 }}
