import { motion } from 'framer-motion';
import { FiCheckCircle, FiClock, FiExternalLink } from 'react-icons/fi';

export default function RevisionPlan({ planData = [] }) {
  if (!planData || planData.length === 0) return null;

  // Map incoming LLM structure to UI expected format
  const formattedPlan = planData.map((dayItem, index) => {
    // LLM might return an array of tasks or a single string task
    let mainTask = '';
    if (dayItem.tasks && Array.isArray(dayItem.tasks)) {
      mainTask = dayItem.tasks[0]?.task || 'Review concepts';
    } else {
      mainTask = dayItem.task || 'Review concepts';
    }

    return {
      day: `Day ${dayItem.day || index + 1}`,
      topic: mainTask,
      duration: dayItem.estimatedHours ? `${dayItem.estimatedHours} hours` : '2 hours',
      concepts: dayItem.topics || ['Fundamentals', 'Practice'],
      status: index === 0 ? 'in-progress' : 'upcoming',
      // Optional resource mapping if available
      resource: dayItem.resource || null
    };
  });

  const getStatusColor = (status) => {
    switch (status) {
      case 'completed':
        return { bg: 'from-green-600 to-green-900', text: 'text-green-400', icon: 'Γ£ô' };
      case 'in-progress':
        return { bg: 'from-orange-600 to-orange-950', text: 'text-orange-400', icon: 'ΓùÅ' };
      case 'upcoming':
        return { bg: 'from-gray-700 to-gray-900', text: 'text-gray-400', icon: 'Γùï' };
      default:
        return { bg: 'from-gray-700 to-gray-900', text: 'text-gray-400', icon: 'Γùï' };
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.1 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, x: -30 },
    visible: { opacity: 1, x: 0, transition: { duration: 0.5 } },
  };

  return (
    <section className="relative min-h-screen pt-20 pb-20 px-4">
      {/* Background Effects */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute top-1/3 right-0 w-80 h-80 bg-orange-600/10 rounded-full blur-3xl"></div>
      </div>

      <div className="relative max-w-5xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="mb-16"
        >
          <h2 className="text-5xl md:text-6xl font-bold text-white mb-4">
            Your Personalized{' '}
            <span className="bg-gradient-to-r from-orange-500 to-orange-300 bg-clip-text text-transparent">
              Revision Plan
            </span>
          </h2>
          <p className="text-xl text-gray-400 max-w-2xl">
            AI-generated 6-day revision schedule tailored to your exam date and weak areas.
          </p>
        </motion.div>

        {/* Timeline */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="relative"
        >
          {/* Vertical Line Container */}
          <div className="hidden md:block absolute left-1/2 transform -translate-x-1/2 w-1 h-full bg-white/10 rounded-full overflow-hidden">
            {/* Background Line (Grey) */}
            <div className="absolute inset-0 bg-gray-800/30"></div>

            {/* Completed Line (Green) */}
            <motion.div
              initial={{ height: 0 }}
              whileInView={{ height: `${(formattedPlan.filter(p => p.status === 'completed').length / formattedPlan.length) * 100}%` }}
              transition={{ duration: 1.5, ease: "easeInOut", delay: 0.5 }}
              className="absolute top-0 left-0 w-full bg-gradient-to-b from-green-500/0 via-green-500 to-green-400 shadow-[0_0_15px_rgba(34,197,94,0.5)]"
            />

            {/* In-Progress Segment (Orange) */}
            <motion.div
              initial={{ height: 0, top: `${(formattedPlan.filter(p => p.status === 'completed').length / formattedPlan.length) * 100}%` }}
              whileInView={{ 
                height: formattedPlan.some(p => p.status === 'in-progress') ? `${(1 / formattedPlan.length) * 100}%` : 0 
              }}
              transition={{ duration: 1, ease: "easeInOut", delay: 2 }}
              className="absolute left-0 w-full bg-gradient-to-b from-orange-500 via-orange-400 to-orange-500 shadow-[0_0_20px_rgba(255,107,0,0.6)] animate-pulse"
            />
          </div>

          <div className="space-y-8">
            {formattedPlan.map((plan, index) => {
              const statusColor = getStatusColor(plan.status);
              const isEven = index % 2 === 0;

              return (
                <motion.div
                  key={index}
                  variants={itemVariants}
                  className="relative"
                >
                  {/* Desktop Layout */}
                  <div className="hidden md:grid md:grid-cols-[1fr_auto_1fr] gap-8 items-center">
                    {/* Left */}
                    <div className="flex justify-end pr-4">
                      {isEven && (
                        <motion.div
                          whileHover={{ x: 10 }}
                          className="group bg-gradient-to-br from-gray-900/50 to-black/50 border border-gray-700/50 rounded-2xl p-6 hover:border-orange-500/50 transition-all duration-300"
                        >
                          <div className="absolute inset-0 bg-gradient-to-br from-orange-600/0 to-transparent rounded-2xl opacity-0 group-hover:opacity-10 transition-opacity duration-300"></div>
                          <div className="relative z-10 space-y-3">
                            <p className="text-sm text-gray-400 font-semibold">{plan.day}</p>
                            <h3 className="text-lg font-bold text-white">{plan.topic}</h3>
                            <div className="flex items-center gap-2 text-gray-400 text-sm">
                              <FiClock size={16} />
                              {plan.duration}
                            </div>
                            <div className="flex flex-wrap gap-2 pt-2">
                              {plan.concepts.map((concept, i) => (
                                <span
                                  key={i}
                                  className="px-3 py-1 bg-orange-500/20 text-orange-300 rounded-full text-xs font-semibold border border-orange-500/30"
                                >
                                  {concept}
                                </span>
                              ))}
                            </div>
                            <ResourceCard resource={plan.resource} />
                          </div>
                        </motion.div>
                      )}
                    </div>

                    {/* Center Node */}
                    <div className="flex justify-center relative z-20">
                      <motion.div
                        initial={{ scale: 0 }}
                        whileInView={{ scale: 1 }}
                        transition={{ delay: index * 0.1, duration: 0.4 }}
                        className={`w-16 h-16 rounded-full bg-gradient-to-br ${statusColor.bg} flex items-center justify-center border-2 border-white shadow-lg shadow-orange-600/50 relative z-20`}
                      >
                        <span className={`text-2xl font-bold text-white`}>{statusColor.icon}</span>
                      </motion.div>
                    </div>

                    {/* Right */}
                    <div className="flex justify-start pl-4">
                      {!isEven && (
                        <motion.div
                          whileHover={{ x: -10 }}
                          className="group bg-gradient-to-br from-gray-900/50 to-black/50 border border-gray-700/50 rounded-2xl p-6 hover:border-orange-500/50 transition-all duration-300"
                        >
                          <div className="absolute inset-0 bg-gradient-to-br from-orange-600/0 to-transparent rounded-2xl opacity-0 group-hover:opacity-10 transition-opacity duration-300"></div>
                          <div className="relative z-10 space-y-3">
                            <p className="text-sm text-gray-400 font-semibold">{plan.day}</p>
                            <h3 className="text-lg font-bold text-white">{plan.topic}</h3>
                            <div className="flex items-center gap-2 text-gray-400 text-sm">
                              <FiClock size={16} />
                              {plan.duration}
                            </div>
                            <div className="flex flex-wrap gap-2 pt-2">
                              {plan.concepts.map((concept, i) => (
                                <span
                                  key={i}
                                  className="px-3 py-1 bg-orange-500/20 text-orange-300 rounded-full text-xs font-semibold border border-orange-500/30"
                                >
                                  {concept}
                                </span>
                              ))}
                            </div>
                            <ResourceCard resource={plan.resource} />
                          </div>
                        </motion.div>
                      )}
                    </div>
                  </div>

                  {/* Mobile Layout */}
                  <div className="md:hidden">
                    <div className="flex gap-4">
                      <motion.div
                        initial={{ scale: 0 }}
                        whileInView={{ scale: 1 }}
                        transition={{ delay: index * 0.1 }}
                        className={`w-12 h-12 rounded-full bg-gradient-to-br ${statusColor.bg} flex items-center justify-center border-2 border-white flex-shrink-0 shadow-lg shadow-orange-600/50`}
                      >
                        <span className="text-lg font-bold text-white">{statusColor.icon}</span>
                      </motion.div>
                      <motion.div
                        whileHover={{ x: 5 }}
                        className="group flex-1 bg-gradient-to-br from-gray-900/50 to-black/50 border border-gray-700/50 rounded-2xl p-4 hover:border-orange-500/50 transition-all duration-300"
                      >
                        <div className="absolute inset-0 bg-gradient-to-br from-orange-600/0 to-transparent rounded-2xl opacity-0 group-hover:opacity-10 transition-opacity duration-300"></div>
                        <div className="relative z-10 space-y-2">
                          <p className="text-sm text-gray-400 font-semibold">{plan.day}</p>
                          <h3 className="text-base font-bold text-white">{plan.topic}</h3>
                          <div className="flex items-center gap-2 text-gray-400 text-xs">
                            <FiClock size={14} />
                            {plan.duration}
                          </div>
                          <div className="flex flex-wrap gap-1 pt-2">
                            {plan.concepts.map((concept, i) => (
                              <span
                                key={i}
                                className="px-2 py-1 bg-orange-500/20 text-orange-300 rounded-full text-xs border border-orange-500/30"
                              >
                                {concept}
                              </span>
                            ))}
                          </div>
                          <ResourceCard resource={plan.resource} />
                        </div>
                      </motion.div>
                    </div>
                  </div>
                </motion.div>
              );
            })}
          </div>
        </motion.div>

        {/* Bottom CTA */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.3 }}
          className="mt-24 mb-16 text-center"
        >
          <motion.button
            whileHover={{ scale: 1.05, boxShadow: '0 0 40px rgba(255, 107, 0, 0.8)' }}
            whileTap={{ scale: 0.95 }}
            className="px-10 py-4 bg-gradient-to-r from-orange-600 to-orange-500 text-white font-bold rounded-xl shadow-lg shadow-orange-600/50 hover:shadow-orange-600/80 transition-all duration-300"
          >
            Download Plan as PDF
          </motion.button>
        </motion.div>
      </div>
    </section>
  );
}

function ResourceCard({ resource }) {
  if (!resource) return null;
  return (
    <div className="mt-4 p-3 bg-black/40 border border-gray-700/50 rounded-xl flex flex-col sm:flex-row sm:items-center justify-between gap-3">
      <div>
        <p className="text-[10px] uppercase tracking-wider text-gray-500 mb-1 font-semibold">Recommended Resource</p>
        <h4 className="text-sm font-bold text-gray-200">{resource.title}</h4>
        <div className="flex flex-wrap gap-2 mt-2">
          <span className={`px-2 py-0.5 rounded text-[10px] font-bold border ${resource.prioClass}`}>{resource.priority}</span>
          <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-blue-500/20 text-blue-400 border border-blue-500/30">{resource.type}</span>
        </div>
      </div>
      <button className="sm:w-auto w-full px-4 py-2 bg-gradient-to-r from-orange-600 to-orange-500 text-white text-xs font-bold rounded-lg shadow-lg shadow-orange-600/20 flex gap-2 items-center justify-center hover:scale-105 transition-transform">
        Open <FiExternalLink size={14} />
      </button>
    </div>
  );
}

import { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { FiUploadCloud, FiFileText, FiImage, FiFile, FiCheckCircle } from 'react-icons/fi';

import LoadingOverlay from '../shared/LoadingOverlay';
import { parseCSV, calculateOverallMetrics } from '../../services/csvParserService';
import { extractTextFromImage } from '../../services/ocrService';
import { extractTextFromPDF } from '../../services/pdfService';
import { detectWeakConcepts } from '../../services/conceptAnalyzerService';
import { generateRecommendations } from '../../services/recommendationService';
import { generateRevisionPlan } from '../../services/llmService';
import { saveTestAttempt } from '../../services/firebaseService';

export default function UploadPanel() {
  const [dragActive, setDragActive] = useState(false);
  const [files, setFiles] = useState([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const fileInputRef = useRef(null);
  const navigate = useNavigate();

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    const droppedFiles = Array.from(e.dataTransfer.files);
    setFiles((prev) => [...prev, ...droppedFiles]);
  };

  const handleChange = (e) => {
    const selectedFiles = Array.from(e.target.files);
    setFiles((prev) => [...prev, ...selectedFiles]);
  };

  const getFileIcon = (fileName) => {
    if (fileName.endsWith('.csv')) return <FiFileText className="text-blue-400" />;
    if (['.png', '.jpg', '.jpeg'].some((ext) => fileName.endsWith(ext)))
      return <FiImage className="text-green-400" />;
    if (fileName.endsWith('.pdf')) return <FiFile className="text-red-400" />;
    return <FiFile className="text-gray-400" />;
  };

  const removeFile = (index) => {
    setFiles((prev) => prev.filter((_, i) => i !== index));
  };

  const handleAnalyze = async () => {
    if (files.length === 0) return;
    setIsAnalyzing(true);

    try {
      let combinedText = '';
      let csvData = null;
      let overallMetrics = null;

      // 1. Process files based on type
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        setLoadingMessage(`Extracting data from ${file.name}...`);
        
        if (file.name.endsWith('.csv')) {
           csvData = await parseCSV(file);
           overallMetrics = calculateOverallMetrics(csvData);
        } else if (file.type.startsWith('image/')) {
           const ocrResult = await extractTextFromImage(file);
           combinedText += ' ' + ocrResult.rawText;
        } else if (file.type === 'application/pdf') {
           const pdfResult = await extractTextFromPDF(file);
           combinedText += ' ' + pdfResult.extractedText;
        }
      }

      // 2. Concept Analysis
      setLoadingMessage('Analyzing concept gaps...');
      let analysis = { weakTopics: [], missingConcepts: [] };
      if (combinedText) {
         analysis = detectWeakConcepts(combinedText);
      }
      
      // Merge CSV metrics if available
      if (overallMetrics && overallMetrics.weakTopics) {
         // Create a simple map to deduplicate weak topics
         const topicMap = new Map();
         analysis.weakTopics.forEach(t => topicMap.set(t.topic, t));
         overallMetrics.weakTopics.forEach(t => {
           if (!topicMap.has(t.topic)) topicMap.set(t.topic, t);
         });
         analysis.weakTopics = Array.from(topicMap.values());
      }

      // 3. Generate Recommendations
      setLoadingMessage('Generating tailored recommendations...');
      const recommendations = generateRecommendations(analysis.weakTopics || []);

      // 4. Generate LLM Revision Plan
      setLoadingMessage('Creating AI-powered study plan...');
      const revisionPlan = await generateRevisionPlan(analysis.weakTopics || [], recommendations);

      // 5. Save to Firebase
      setLoadingMessage('Saving your results...');
      const studentEmail = 'student@example.com'; // Demo email
      const testData = {
         fileType: files[0].name.split('.').pop(),
         rawData: { text: combinedText, csv: csvData },
         overallScore: overallMetrics?.overallPercentage || 0,
         totalMarksObtained: overallMetrics?.totalMarksObtained || 0,
         totalMarksAvailable: overallMetrics?.maxMarks || 0, // Using maxMarks based on csvParserService
         weakConcepts: analysis.weakTopics || [],
         missingConcepts: analysis.missingConcepts || [],
         recommendations: recommendations || [],
         revisionPlan: revisionPlan || []
      };

      const docId = await saveTestAttempt('Demo Student', studentEmail, testData);

      // 6. Redirect to Analysis page
      setLoadingMessage('Done! Redirecting...');
      setTimeout(() => {
        setIsAnalyzing(false);
        navigate(`/analysis?id=${docId}`);
      }, 1000);

    } catch (error) {
      console.error('Analysis failed:', error);
      setIsAnalyzing(false);
      alert('Analysis failed: ' + error.message);
    }
  };

  return (
    <section
      id="upload"
      className="w-full relative min-h-[80vh] pt-16 pb-16 px-4 sm:px-6 lg:px-8 flex flex-col justify-center"
      style={{
        background:
          'radial-gradient(ellipse 80% 60% at 50% 0%, rgba(255,110,0,0.18), transparent 70%), radial-gradient(ellipse 60% 60% at 80% 100%, rgba(139,92,246,0.12), transparent 70%), transparent',
      }}
    >
      <LoadingOverlay isVisible={isAnalyzing} message={loadingMessage} />
      {/* Decorative blobs */}
      <div className="pointer-events-none absolute inset-0 overflow-hidden">
        <div className="absolute top-16 left-1/2 -translate-x-1/2 w-[600px] h-[400px] bg-orange-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-24 right-1/4 w-72 h-72 bg-purple-500/10 rounded-full blur-3xl" />
      </div>

      {/* ΓöÇΓöÇ Centered content column ΓöÇΓöÇ */}
      <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center">

        {/* ΓöÇΓöÇ Hero heading ΓöÇΓöÇ */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.7 }}
          className="w-full text-center mb-8"
        >
          <h1 className="text-4xl sm:text-5xl md:text-6xl font-black leading-tight mb-4 tracking-tight">
            <span className="text-white">Upload Your </span>
            <span className="bg-gradient-to-r from-orange-400 via-orange-500 to-yellow-300 bg-clip-text text-transparent">
              Exam Data
            </span>
          </h1>
          <p className="text-gray-300 text-base md:text-lg leading-relaxed mb-2">
            Unlock AI-powered insights from your exam performance.
            Upload marksheets, answer sheets, and more.
          </p>
          <p className="text-gray-500 text-sm">
            Get instant analysis, weakness detection, and personalized study plans
          </p>
        </motion.div>

        {/* ΓöÇΓöÇ Upload Card ΓöÇΓöÇ */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.15 }}
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
          className={`w-full rounded-3xl transition-all duration-300 mb-10 ${
            dragActive
              ? 'border-2 border-orange-400 shadow-2xl shadow-orange-500/40 bg-gradient-to-br from-orange-950/40 to-black/60'
              : 'border-2 border-gray-700/60 shadow-2xl shadow-black/40 bg-gradient-to-br from-gray-900/50 via-black/60 to-black/80 hover:border-orange-500/50 hover:shadow-orange-600/20'
          }`}
        >
          <div className="block py-5 px-6">
            <div className="flex flex-col items-center justify-center gap-3">

              {/* Upload icon */}
              <motion.div
                animate={dragActive ? { scale: 1.15, rotate: 10 } : { scale: 1, rotate: 0 }}
                transition={{ type: 'spring', stiffness: 200, damping: 15 }}
                className="relative"
              >
                <div className="absolute inset-0 bg-gradient-to-br from-orange-500 to-yellow-400 rounded-full blur-xl opacity-25" />
                <FiUploadCloud className="text-5xl md:text-6xl text-orange-400 relative z-10 drop-shadow-xl" />
              </motion.div>

              {/* Text */}
              <div className="text-center space-y-1">
                <h2 className="text-xl md:text-2xl font-bold text-white">
                  Drag &amp; drop your files
                </h2>
                <p className="text-gray-300 text-base">
                  or{' '}
                  <span onClick={() => fileInputRef.current?.click()} className="text-orange-400 font-semibold cursor-pointer hover:underline">click to browse</span>
                </p>
                <p className="text-xs text-gray-500">
                  CSV, PNG, JPG, JPEG, PDF ΓÇö exam data pipeline in one step
                </p>
              </div>

              {/* File type badges */}
              <div className="flex flex-wrap gap-2 justify-center">
                {[
                  { icon: '≡ƒôè', label: 'CSV Sheets', color: 'from-blue-600/30' },
                  { icon: '≡ƒô╕', label: 'Answer Images', color: 'from-green-600/30' },
                  { icon: '≡ƒôä', label: 'PDF Files', color: 'from-red-600/30' },
                ].map((type, idx) => (
                  <motion.span
                    key={idx}
                    whileHover={{ scale: 1.08, y: -2 }}
                    className={`px-3 py-1.5 rounded-full bg-gradient-to-r ${type.color} to-transparent border border-gray-700/50 text-xs font-medium text-gray-200`}
                  >
                    {type.icon} {type.label}
                  </motion.span>
                ))}
              </div>

              {/* Browse Button ΓÇö inside flex column so it's never clipped */}
              <motion.button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                whileHover={{ scale: 1.05, boxShadow: '0 0 20px rgba(255,155,0,0.7)' }}
                whileTap={{ scale: 0.97 }}
                className="px-6 py-2.5 mt-2 rounded-full bg-gradient-to-r from-orange-600 to-orange-500 text-white font-bold shadow-lg shadow-orange-600/40 transition-all duration-300 text-sm cursor-pointer"
              >
                Browse Files
              </motion.button>
            </div>

            <input
              ref={fileInputRef}
              type="file"
              multiple
              accept=".csv,.png,.jpg,.jpeg,.pdf"
              onChange={handleChange}
              className="hidden"
            />
          </div>
        </motion.div>

        {/* ΓöÇΓöÇ Uploaded files list ΓöÇΓöÇ */}
        {files.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4 }}
            className="w-full mb-10 space-y-4"
          >
            <h3 className="text-xl font-bold text-white flex items-center gap-2">
              <FiCheckCircle className="text-green-400" />
              Uploaded Files ({files.length})
            </h3>
            <div className="space-y-3">
              {files.map((file, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.08 }}
                  whileHover={{ x: 6 }}
                  className="flex items-center justify-between bg-gray-900/60 border border-gray-700/60 rounded-2xl p-4 hover:border-orange-500/40 transition-all duration-300"
                >
                  <div className="flex items-center gap-3 flex-1">
                    <div className="text-2xl">{getFileIcon(file.name)}</div>
                    <div className="flex-1 min-w-0">
                      <p className="text-white font-semibold truncate">{file.name}</p>
                      <p className="text-gray-400 text-xs">
                        {(file.size / 1024 / 1024).toFixed(2)} MB
                      </p>
                    </div>
                  </div>
                  <motion.button
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => removeFile(index)}
                    className="px-3 py-1.5 text-red-400 hover:bg-red-500/20 rounded-lg text-sm font-medium transition-colors"
                  >
                    Remove
                  </motion.button>
                </motion.div>
              ))}
            </div>

            <motion.button
              onClick={handleAnalyze}
              disabled={isAnalyzing}
              whileHover={{ scale: 1.02, boxShadow: '0 0 40px rgba(255,107,0,0.8)' }}
              whileTap={{ scale: 0.98 }}
              className="w-full mt-4 py-4 bg-gradient-to-r from-orange-600 to-orange-500 text-white font-bold rounded-2xl shadow-xl shadow-orange-600/50 transition-all duration-300 text-base disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isAnalyzing ? 'Analyzing...' : 'Analyze Now'}
            </motion.button>
          </motion.div>
        )}

        {/* ΓöÇΓöÇ AI-Powered Features ΓöÇΓöÇ */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="w-full mb-10"
        >
          <h2 className="text-2xl md:text-3xl font-bold text-white text-center mb-8">
            AI-Powered Features
          </h2>
          <div className="grid grid-cols-2 gap-4">
            {[
              { icon: '≡ƒôè', title: 'CSV Analysis', desc: 'Auto-parse exam scorecards' },
              { icon: '≡ƒô╖', title: 'OCR Detection', desc: 'Extract handwritten answers' },
              { icon: '≡ƒºá', title: 'Weakness AI', desc: 'Spot concept gaps instantly' },
              { icon: '≡ƒÄ»', title: 'Study Plans', desc: 'Personalized revision paths' },
            ].map((feature, idx) => (
              <motion.div
                key={idx}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ delay: idx * 0.1, duration: 0.4 }}
                whileHover={{ y: -6 }}
                className="group relative rounded-2xl border border-gray-700/50 bg-gradient-to-br from-gray-900/60 to-black/70 p-5 text-center hover:border-orange-500/40 transition-all duration-300"
              >
                <div className="text-4xl mb-2">{feature.icon}</div>
                <h3 className="text-sm font-bold text-white mb-1">{feature.title}</h3>
                <p className="text-xs text-gray-400">{feature.desc}</p>
              </motion.div>
            ))}
          </div>
        </motion.div>

        {/* ΓöÇΓöÇ Quick Stats ΓöÇΓöÇ */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="w-full"
        >
          <h2 className="text-2xl md:text-3xl font-bold text-white text-center mb-8">
            Quick Stats
          </h2>
          <div className="grid grid-cols-2 gap-4">
            {[
              { label: 'Tests Analyzed', value: '14' },
              { label: 'Weak Concepts', value: '8' },
              { label: 'Progress', value: '63%' },
              { label: 'Recommendations', value: '27' },
            ].map((stat, idx) => (
              <motion.div
                key={idx}
                initial={{ opacity: 0, scale: 0.9 }}
                whileInView={{ opacity: 1, scale: 1 }}
                transition={{ delay: idx * 0.08, duration: 0.4 }}
                whileHover={{ y: -4 }}
                className="rounded-2xl border border-gray-700/60 bg-gradient-to-br from-gray-900/60 to-black/80 p-5 text-center hover:border-orange-500/40 transition-all duration-300"
              >
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-semibold mb-2">
                  {stat.label}
                </p>
                <p className="text-3xl font-black text-orange-400">{stat.value}</p>
              </motion.div>
            ))}
          </div>
        </motion.div>

      </div>
    </section>
  );
}

import { motion } from 'framer-motion';
import { FiTrendingUp } from 'react-icons/fi';
export default function WeaknessDashboard() {
  const weaknesses = [
    { concept: 'CPU Scheduling', score: 35, risk: 'High', color: 'from-red-600' },
    { concept: 'Memory Management', score: 42, risk: 'High', color: 'from-red-500' },
    { concept: 'Paging', score: 48, risk: 'Medium', color: 'from-yellow-600' },
    { concept: 'File Systems', score: 55, risk: 'Medium', color: 'from-yellow-500' },
    { concept: 'Process Synchronization', score: 62, risk: 'Low', color: 'from-green-600' },
    { concept: 'Deadlock', score: 78, risk: 'Low', color: 'from-green-500' },
  ];

  const getRiskColor = (risk) => {
    switch (risk) {
      case 'High':
        return 'text-red-400';
      case 'Medium':
        return 'text-yellow-400';
      case 'Low':
        return 'text-green-400';
      default:
        return 'text-gray-400';
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.1 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.4 } },
  };

  return (
    <section className="relative min-h-screen pt-20 pb-20 px-4">
      {/* Background Effects */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute top-1/2 -right-40 w-80 h-80 bg-orange-600/10 rounded-full blur-3xl"></div>
      </div>

      <div className="relative max-w-6xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="mb-8"
        >
          <h3 className="text-2xl md:text-3xl font-bold text-white flex items-center gap-2">
            <FiTrendingUp className="text-orange-500" /> Concept Improvements
          </h3>
        </motion.div>

        {/* Dashboard Grid */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
        >
          {weaknesses.map((weak, index) => (
            <motion.div
              key={index}
              variants={itemVariants}
              whileHover={{ y: -8, boxShadow: '0 20px 40px rgba(255, 107, 0, 0.2)' }}
              className="group relative bg-gradient-to-br from-gray-900/50 to-black/50 border border-gray-700/50 rounded-2xl p-6 hover:border-orange-500/50 transition-all duration-300 overflow-hidden"
            >
              {/* Glow Background */}
              <div
                className={`absolute inset-0 bg-gradient-to-br ${weak.color} to-transparent opacity-0 group-hover:opacity-10 transition-opacity duration-300`}
              ></div>

              <div className="relative z-10 space-y-4">
                {/* Header */}
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="text-lg font-bold text-white mb-1">{weak.concept}</h3>
                    <p className={`text-sm font-semibold ${getRiskColor(weak.risk)}`}>
                      {weak.risk} Risk
                    </p>
                  </div>
                  <motion.div
                    initial={{ scale: 0 }}
                    whileInView={{ scale: 1 }}
                    transition={{ delay: 0.3 + index * 0.05 }}
                    className={`w-12 h-12 rounded-full bg-gradient-to-br ${weak.color} to-transparent flex items-center justify-center`}
                  >
                    <span className="text-white font-bold text-lg">{weak.score}%</span>
                  </motion.div>
                </div>

                {/* Progress Bar */}
                <div className="space-y-2">
                  <div className="h-2 bg-gray-700/50 rounded-full overflow-hidden">
                    <motion.div
                      initial={{ width: 0 }}
                      whileInView={{ width: `${weak.score}%` }}
