};

/**
 * Parse questions from text response
 * @param {string} text - Text response
 * @returns {Array} Questions array
 */
const parseQuuestionsFromText = (text) => {
  const questions = [];
  const questionRegex = /question\s*\d+:?(.*?)(?=question\s*\d+|$)/gis;
  const matches = [...text.matchAll(questionRegex)];

  matches.forEach((match, index) => {
    questions.push({
      number: index + 1,
      content: match[1].trim(),
    });
  });

  return questions;
};

